import { getContext, setContext } from 'svelte'
import type { StoreCart } from '@medusajs/types'
import type { CartLine } from './types.js'

export type CartContext = {
	readonly cart: StoreCart | null | undefined
	readonly loading: boolean
	readonly error: unknown
	readonly count: number
	readonly lineCount: number
	readonly subtotal: number | undefined
	readonly pending: boolean
	readonly checkoutUrl: string
	lineHref: (item: CartLine) => string
	updateItem: (itemId: string, quantity: number) => Promise<void>
	removeItem: (itemId: string) => Promise<void>
}
export type LineItemContext = { readonly item: CartLine }

const CART = Symbol('cart')
const LINE = Symbol('cart-line-item')

export function setCartContext(ctx: CartContext) {
	setContext(CART, ctx)
}
export function getCartContext(): CartContext {
	const ctx = getContext<CartContext>(CART)
	if (!ctx) throw new Error('Cart.* must be used within <Cart.Root>')
	return ctx
}
export function getCartContextOptional(): CartContext | null {
	return getContext<CartContext>(CART) ?? null
}
export function setLineItemContext(ctx: LineItemContext) {
	setContext(LINE, ctx)
}
export function getLineItemContext(): LineItemContext {
	const ctx = getContext<LineItemContext>(LINE)
	if (!ctx) throw new Error('Cart line parts must be used within <Cart.LineItem>')
	return ctx
}

import type { StoreCart } from '@medusajs/types'
import type { CartLine, LineHrefFn } from './types.js'

export function totalQuantity(cart: StoreCart | null | undefined): number {
	return (cart?.items ?? []).reduce((n, li) => n + (li.quantity ?? 0), 0)
}
export function lineCount(cart: StoreCart | null | undefined): number {
	return cart?.items?.length ?? 0
}
export function subtotal(cart: StoreCart | null | undefined): number | undefined {
	return (cart as { item_subtotal?: number } | null | undefined)?.item_subtotal ?? undefined
}
export const defaultLineHref: LineHrefFn = (item: CartLine) =>
	`/product/${item.product_handle}${item.variant_id ? `?variant=${item.variant_id}` : ''}`

// Medusa returns amounts in major units. `locale` is pinned (default 'en-US') so server + client
// render identically (avoids a hydration mismatch from host-locale differences).
export function formatPrice(
	amount: number | null | undefined,
	currencyCode: string | null | undefined,
	locale = 'en-US'
): string {
	if (amount == null || !currencyCode) return ''
	return new Intl.NumberFormat(locale, { style: 'currency', currency: currencyCode.toUpperCase() }).format(amount)
}

import type { StoreCart } from '@medusajs/types'

export type CartLine = NonNullable<StoreCart['items']>[number]

// getCart is a SvelteKit remote query — awaitable AND exposing `.current`/`.loading`/`.error`.
// Typed structurally so tests can inject a fake `{ current }`.
export type CartQuery = { current: StoreCart | null | undefined; loading?: boolean; error?: unknown }
export type GetCartFn = () => CartQuery
export type UpdateCartItemFn = (args: { item_id: string; quantity: number }) => Promise<StoreCart | null>
export type RemoveFromCartFn = (lineId: string) => Promise<StoreCart | null>
export type LineHrefFn = (item: CartLine) => string
